const orders = $input.first().json.orders || [];
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);
const totalOrders = orders.length;
const avgOrderValue = totalOrders > 0 ? (totalRevenue / totalOrders).toFixed(2) : 0;

const topProducts = {};
for (const order of orders) {
  for (const item of (order.line_items || [])) {
    topProducts[item.title] = (topProducts[item.title] || 0) + item.quantity;
  }
}
const top3 = Object.entries(topProducts)
  .sort((a,b) => b[1]-a[1])
  .slice(0,3)
  .map(([name,qty]) => `${name} (${qty}x)`);

const yesterday = new Date();
yesterday.setDate(yesterday.getDate()-1);
const dateStr = yesterday.toLocaleDateString('en-MY', {day:'numeric',month:'short'});

return [{ json: { date: dateStr, total_orders: totalOrders, total_revenue: 'RM ' + totalRevenue.toFixed(2), avg_order_value: 'RM ' + avgOrderValue, top_products: top3 } }];

